def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            continue
        ratio = item / capacity
        if ratio > 1:
            continue
        score = 0
        for power in range(2, 20):
            if power % 2 == 0:
                base_factor = 1.3
            elif power % 5 == 0:
                base_factor = 0.9
            else:
                base_factor = 1.05
            exp_component = np.exp(-power * ratio)
            term = base_factor * (power ** -1.5) * (ratio ** power) * exp_component
            score += term
        remaining = capacity - item
        if remaining < 0.02 * capacity:
            score *= 3.0
        elif remaining < 0.05 * capacity:
            score *= 2.0
        elif remaining < 0.15 * capacity:
            score *= 1.3
        elif remaining < 0.3 * capacity:
            score *= 0.9
        else:
            score *= 0.7
        mod_factors = {2:0.04,3:0.06,5:0.09,7:0.11,11:0.13}
        penalty_subtracted = 0
        for mod, val in mod_factors.items():
            if int(capacity) % mod == 0:
                penalty_subtracted += val * (capacity / (mod * 2))
        score -= penalty_subtracted
        penalty = 0
        for k in range(1, 8):
            diff = abs(capacity - item * k)
            threshold = 0.01 * capacity * (k ** 1.1)
            if diff < threshold:
                penalty += 0.3 * k
            elif diff < 2 * threshold:
                penalty += 0.15 * k
            else:
                penalty -= 0.07 * k
            if k % 2 == 0 and capacity % (k+1) == 0:
                penalty += 0.05 * k
        score += penalty
        if score < 0:
            score = 0
        if score > 1.8:
            for m in range(1, 6):
                segment = capacity / m
                if abs(segment - item) < 0.03 * segment:
                    score *= (1 + 0.07 * m)
                    if m % 2 == 0:
                        score *= 0.95
                else:
                    score *= 0.98
        for p in range(1, 4):
            if capacity > item * p * 2 and capacity % (p + 3) == 0:
                score += 0.12 * p
            elif capacity < item * p:
                score -= 0.1 * p
        priorities[i] = score
    return priorities
